                    if '/' in code:
                        main_group = code.split('/')[0]
                    else:
                        main_group = code
                    test_code = main_group
                    while len(test_code) > 3:
                        if test_code in level5_symbols:
                            level5_codes.add(test_code)
                            break
                        test_code = test_code[:-1]

