    best_year = max(ema.items(), key=lambda x: x[1])

    cpc_ema_values[cpc] = ema
    cpc_best_year[cpc] = {
        'best_year': best_year[0],
        'best_ema': best_year[1],
        'max_raw_count': max(yearly_data.values())
